// Get original data from Dev Data Injector
// (Previous nodes only passed validation flags, not original data)
const originalData = $('Session Context Builder').first().json;

return [{
  json: {
    sessionId: originalData.sessionId,
    phoneNumber: originalData.phoneNumber,
    chatInput: originalData.chatInput,
    action: originalData.action,
    quotationId: null,
    hasQuotationId: false,
    shouldShowFallback: true,
    conversationPhase: 'fallback',
    isNewSession: true,
    sessionData: null
  }
}];

const allItems = $input.all();
const item = allItems[0];
const data = item.json;

let output;

// Ruta 1: Fallback Flag -- no se encontro sesion / usuario nuevo
if (data.shouldShowFallback !== undefined) {
  output = {
    ...data,
    conversationId: null,
    leadId: null,
    status: 'new',
    outOfScopeAttempts: 0,
    isBanned: false
  };
}
// Ruta 2: Update Activity -- sesion resuelta por Resolve Session/Session Resolution
else {
  const resolution = $('Session Resolution').first().json;
  const sessionRow = resolution.sessionRow;
  const rateLimitData = sessionRow.rate_limit_data || {};

  output = {
    sessionId: sessionRow.session_id,
    phoneNumber: sessionRow.phone_number,
    chatInput: resolution.chatInput,
    action: resolution.action,
    hasQuotationId: true,
    quotationId: sessionRow.quotation_id?.toString() ?? null,
    conversationId: sessionRow.conversation_id || (sessionRow.session_id?.startsWith('waq_') ? sessionRow.session_id : null),
    leadId: sessionRow.lead_id?.toString() ?? null,
    status: sessionRow.status || 'open',
    conversationPhase: sessionRow.conversation_phase,
    rateLimitData: rateLimitData,
    sessionData: {
      sessionId: sessionRow.session_id,
      phoneNumber: sessionRow.phone_number,
      quotationId: sessionRow.quotation_id,
      conversationPhase: sessionRow.conversation_phase,
      quotationData: sessionRow.quotation_data,
      capturedData: sessionRow.captured_data,
      policyData: sessionRow.policy_data,
      lastActivity: sessionRow.last_activity,
      rateLimitData: rateLimitData
    },
    outOfScopeAttempts: sessionRow.out_of_scope_attempts || 0,
    isBanned: sessionRow.is_banned || false,
    shouldShowFallback: false,
    isNewSession: false
  };
}

return [{json: output}];

// ============================================
// SESSION CONTEXT BUILDER - conversation_id aware
// ============================================
// Parsea el webhook de Meta. NO consulta Postgres -- la resolucion
// contra whatsapp_sessions ocurre en Resolve Session.
// ============================================

const inputData = $input.first().json;

const message = inputData.messages?.[0]
  || inputData.entry?.[0]?.changes?.[0]?.value?.messages?.[0]
  || inputData.body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]
  || {};

const phoneNumberRaw = message?.from || "";

function normalizeMexicanMobile(number) {
  if (number.startsWith("521") && number.length === 13) {
    return "52" + number.substring(3);
  }
  return number;
}

const phoneNumber = normalizeMexicanMobile(phoneNumberRaw);
const action = "sendMessage";

let buttonPayload = null;
let chatInput = "";
let hasImage = false;
let imageMediaId = null;

if (message.type === "interactive" && message.interactive?.type === "button_reply") {
  // Nunca usar button_reply.title para logica de negocio -- solo .id
  buttonPayload = message.interactive.button_reply.id || null;
  chatInput = "Continuar cotización";
} else if (message.type === "button" && message.button?.payload) {
  // Boton de respuesta rapida sobre un mensaje de plantilla (shape distinto
  // al interactive.button_reply nativo). Nunca usar button.text para logica
  // de negocio -- solo .payload.
  buttonPayload = message.button.payload || null;
  chatInput = "Continuar cotización";
} else if (message.type === "image") {
  // Extracción de VIN por foto (handoff 2026-07-14). Nunca dejar chatInput vacío aquí
  // -- si no hay media id, la rama de extracción cae a su propio fallback de texto,
  // no a "" (regresión de issue #33).
  imageMediaId = message.image?.id || null;
  hasImage = true;
  chatInput = "[imagen recibida, procesando]";
} else if (["sticker", "video", "audio", "document", "location", "contacts"].includes(message.type)) {
  // Da contexto explícito al agente para que responda algo relevante sobre lo que
  // el cliente realmente envió, en vez de recibir un turno vacío y tener que
  // adivinar (handoff 2026-07-17-handoff-fallback-media-no-soportada).
  const mediaLabels = {
    sticker: "un sticker",
    video: "un video",
    audio: "una nota de voz o audio",
    document: "un documento",
    location: "su ubicación",
    contacts: "una tarjeta de contacto",
  };
  chatInput = `[MEDIA_NO_SOPORTADA] El cliente envió ${mediaLabels[message.type]}. Este tipo de contenido no se puede procesar, solo texto y fotos.`;
} else {
  chatInput = message?.text?.body || "";
}

function parsePayload(payload) {
  // "qc:v2:cv:<id>:l:<id>:c:<id>:m:<hex>" -> {cv,l,c,m}
  const parts = payload.split(":");
  const rest = parts.slice(2);
  const idx = {};
  for (let i = 0; i < rest.length - 1; i += 2) idx[rest[i]] = rest[i + 1];
  return idx;
}

let conversationId = null;
let quotationId = null;
let leadId = null;
let payloadVersion = null;
let lookupMode = "phone_open_sessions";
let sessionId = phoneNumber;

if (buttonPayload && buttonPayload.startsWith("qc:v2:")) {
  const idx = parsePayload(buttonPayload);
  conversationId = idx.cv || null;
  leadId = idx.l || null;
  quotationId = idx.c || null;
  payloadVersion = "v2";
  lookupMode = "payload_v2";
  sessionId = conversationId;
} else if (buttonPayload && buttonPayload.startsWith("qc:v1:")) {
  const idx = parsePayload(buttonPayload);
  quotationId = idx.c || null;
  payloadVersion = "v1";
  lookupMode = "payload_v1";
  // sessionId final se resuelve en Resolve Session
}

return [{
  json: {
    sessionId,
    inboundMessageId: message?.id || null,
    action,
    chatInput,
    phoneNumber,
    conversationId,
    quotationId,
    leadId,
    payloadVersion,
    lookupMode,
    buttonPayload,
    hasImage,
    imageMediaId,
    metadata: inputData.metadata
  }
}];

// CRITICAL: In Code Tool nodes, AI Agent passes parameters through $input
// Extract the dataToValidate parameter from the input
const inputData = $input.first().json;
const dataToValidate = inputData.dataToValidate || {};

// Debug: Log what we received (remove after testing)
console.log('Received input:', JSON.stringify(inputData, null, 2));
console.log('dataToValidate:', JSON.stringify(dataToValidate, null, 2));

// Validation function
function validatePersonalData(data) {
  const errors = {};
  let hasErrors = false;

  // Email validation
  if (data.email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(data.email)) {
      errors.email = "Formato inválido. Ejemplo: usuario@ejemplo.com";
      hasErrors = true;
    }
  }

  // Phone validation (10 digits)
  if (data.telefono) {
    const phoneRegex = /^\d{10}$/;
    if (!phoneRegex.test(data.telefono)) {
      errors.telefono = "Debe tener exactamente 10 dígitos. Ejemplo: 5563125678";
      hasErrors = true;
    }
  }

  if (data.numero_identificacion) {
    const ineRegex = /^\d{10}$/;
    if (!ineRegex.test(data.numero_identificacion)) {
      errors.numero_identificacion = "Debe tener exactamente 10 dígitos. Ejemplo: 1152444889";
      hasErrors = true;
    }
  }

  // Date of birth validation (DD/MM/AAAA) and age >= 18
  if (data.fecha_nacimiento) {
    const dateRegex = /^(\d{2})\/(\d{2})\/(\d{4})$/;
    const match = data.fecha_nacimiento.match(dateRegex);

    if (!match) {
      errors.fecha_nacimiento = "Formato inválido. Ejemplo: 03/12/1992 (DD/MM/AAAA)";
      hasErrors = true;
    } else {
      const [_, day, month, year] = match;
      const birthDate = new Date(year, month - 1, day);
      const today = new Date();
      let age = today.getFullYear() - birthDate.getFullYear();
      const monthDiff = today.getMonth() - birthDate.getMonth();

      if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
        age--;
      }

      if (age < 18) {
        errors.fecha_nacimiento = "Debe ser mayor de 18 años";
        hasErrors = true;
      } else if (age > 90) {
        errors.fecha_nacimiento = "La edad máxima permitida es de 90 años";
        hasErrors = true;
      }
    }
  }

  // RFC validation (4 letters + 6 digits + 3 alphanumeric)
  if (data.rfc) {
    const rfcRegex = /^[A-ZÑ&]{4}\d{6}([A-Z0-9]{3})?$/;
    if (!rfcRegex.test(data.rfc.toUpperCase())) {
      errors.rfc = "Formato inválido. Debe ser 10 chars (PEGJ900515) o 13 chars (PEGJ900515ABC)";
      hasErrors = true;
    }
  }

  // Placas validation (opcionales, 6-7 caracteres alfanumericos si se proporcionan)
  if (data.placas) {
    const placasRegex = /^[A-Z0-9]{6,7}$/;
    if (!placasRegex.test(data.placas.toUpperCase())) {
      errors.placas = "Formato inválido. Debe ser 6 o 7 caracteres alfanuméricos (ej. ABC123 o ABC1234)";
      hasErrors = true;
    }
  }

  if (data.serie) {
    const serieNorm = String(data.serie).trim().toUpperCase();
    const vinRegex = /^[A-HJ-NPR-Z0-9]{8}[0-9X][A-HJ-NPR-Z0-9]{8}$/;
    if (!vinRegex.test(serieNorm)) {
      errors.serie = "El número de serie (NIV/VIN) debe tener exactamente 17 caracteres, sin espacios ni guiones y sin las letras I, O ni Q (el 9º carácter es un dígito o X). Ejemplo: 3VWFE21C04M000001";
      hasErrors = true;
    }
  }

  // Postal code validation (5 digits)
  if (data.codigo_postal) {
    const cpRegex = /^\d{5}$/;
    if (!cpRegex.test(data.codigo_postal)) {
      errors.codigo_postal = "Debe tener exactamente 5 dígitos. Ejemplo: 01460";
      hasErrors = true;
    }
  }

  // Gender validation (optional - M or F)
  if (data.genero) {
    const validGenders = ['M', 'F'];
    if (!validGenders.includes(data.genero.toUpperCase())) {
      errors.genero = "Debe ser M (masculino) o F (femenino)";
      hasErrors = true;
    }
  }

  return {
    valid: !hasErrors,
    errors: errors
  };
}

// Execute validation
const result = validatePersonalData(dataToValidate);

// CRITICAL: Code Tools must return STRING, not objects
// AI Agents expect human-readable text responses they can interpret
if (!result.valid) {
  // Format errors as readable text for the AI Agent
  let errorMessage = "Validation failed with the following errors:\n";

  for (const [field, message] of Object.entries(result.errors)) {
    errorMessage += `- ${field}: ${message}\n`;
  }

  return errorMessage;
} else {
  return "Validation successful: All personal data fields are correctly formatted.";
}

