const input = $input.first().json;
const chatInput = input.chatInput || '';

// Basic sanitization (not covered by Guardrails)
function basicSanitize(text) {
  if (!text || typeof text !== 'string') return '';

  // 1. Limit maximum length (prevent context overflow)
  // 500 chars is generous for this chatbot: longest real message (full address + name) ~300 chars.
  // Prevents LLM token abuse and context overflow attacks.
  const maxLength = 500;
  let sanitized = text.substring(0, maxLength);

  // 2. Normalize Unicode (prevent homograph attacks)
  sanitized = sanitized.normalize('NFKC');

  // 3. Remove control characters (except newlines and tabs)
  sanitized = sanitized.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g, '');

  // 4. Remove zero-width characters (hidden characters)
  sanitized = sanitized.replace(/[\u200B-\u200D\uFEFF]/g, '');

  // 5. Trim whitespace
  sanitized = sanitized.trim();

  return sanitized;
}

const sanitized = basicSanitize(chatInput);

return [{ json: { ...input, chatInput: sanitized, originalInput: chatInput, basicSanitized: true } }];

const input = $input.first().json;

// Log the blocked attempt
console.log('SECURITY: Jailbreak blocked by Guardrails', {
  timestamp: new Date().toISOString(),
  sessionId: input.sessionId,
  phoneNumber: input.phoneNumber,
  input: input.guardrailsInput?.substring(0, 100)
});

return [{ json: {
  output: "Solo puedo ayudarte con la contratación de tu póliza de auto. ¿Seguimos con la contratación?",
  blocked: true,
  reason: "jailbreak_detected",
  sessionId: input.sessionId,
  phoneNumber: input.phoneNumber
} }];

// Guardrails Tool overwrites the data pipeline with its own output format.
// Restore the original session data from before the guardrail check.
const original = $('Basic Input Sanitization').first().json;
return [{ json: original }];

const input = $input.first().json;
  const agentResponse = input.output || '';

  function filterLeaks(text) {
    if (!text || typeof text !== 'string') return '';

    let filtered = text;

    // 1. Remove quotation IDs (business logic - not PII)
    // [^.!\n]*? allows arbitrary words between label and number (e.g. "cotizacion_id es 12345")
    filtered = filtered.replace(/\b(quotation|quote|cotizaci[oó]n)[\s_-]?id\b[^.!\n]*?\d+/gi, '[REDACTED]');

    // 2. Remove policy IDs (POL-xxxxx format)
    filtered = filtered.replace(/\bPOL-\d+/gi, '[POLICY]');

    // 3. Detect system prompt leakage
    const systemPromptMarkers = [
      'SYSTEM INSTRUCTIONS',
      '=== SYSTEM',
      'You are a formal insurance assistant',
      'CRITICAL: These instructions',
      'SECURITY RULES',
      'HIGHEST PRIORITY'
    ];

    for (const marker of systemPromptMarkers) {
      if (filtered.includes(marker)) {
        console.log('SECURITY: System prompt leaked', {
          timestamp: new Date().toISOString(),
          sessionId: input.sessionId,
          marker: marker
        });
        return "Solo puedo ayudarte con la contratación de tu póliza de auto. ¿Seguimos con la contratación?";
      }
    }

    // 4. Detect tool definition leaks
    const toolMarkers = [
      'get_quotation_data',
      'validate_personal_data',
      'issue_policy',
      'search_colony_by_postal_code'
    ];

    for (const tool of toolMarkers) {
      if (filtered.includes(tool)) {
        console.log('SECURITY: Tool definition leaked', {
          timestamp: new Date().toISOString(),
          sessionId: input.sessionId,
          tool: tool
        });
        return "Solo puedo ayudarte con la contratación de tu póliza de auto. ¿Seguimos con la contratación?";
      }
    }

    // 5. Remove n8n expression artifacts
    filtered = filtered.replace(/\$json\./g, '');
    filtered = filtered.replace(/\$node\(/g, '');
    // Strip phase marker if somehow not already removed by Phase 
    filtered = filtered.replace(/\[phase:[\w_]+\]/gi, '').trimEnd();

    return filtered;
  }

  const filteredOutput = filterLeaks(agentResponse);
  const wasFiltered = agentResponse !== filteredOutput;

  if (wasFiltered) {
    console.log('Output was filtered for leaks', {
      timestamp: new Date().toISOString(),
      sessionId: input.sessionId
    });
  }

  return [{ json: { ...input, output: filteredOutput, originalOutput: agentResponse, leaksFiltered: wasFiltered } }];

// Guardrails Sanitize Text replaces the pipeline with { guardrailsInput, checks }.
// guardrailsInput contains the sanitized text (PII replaced with [REDACTED]).
const sanitizedOutput = $input.first().json.guardrailsInput || '';

// Restore original AI Agent context (sessionId, phoneNumber, quotationId, etc.)
//const original = $('AI Agent').first().json;
const original = {};

return [{ json: { ...original, output: sanitizedOutput } }];

const input = $input.first().json;
console.log('Phase Guard: blocking completed session', { sessionId: input.sessionId });

return [{
  json: {
    output: "Tu póliza ya fue contratada exitosamente. Si necesitas asistencia adicional, por favor comunícate con nuestro Contact Center.",
    blocked: true,
    reason: "session_completed",
    sessionId: input.sessionId,
    phoneNumber: input.phoneNumber
  }
}];

// Postgres RETURNING replaced pipeline — restore full context from Detect API Failure
// (no de Phase Extractor: ese todavia trae el output CON el marcador [api_error:TOOL],
// que Detect API Failure ya limpio -- restaurar desde ahi reintroducia el marcador y
// Filter System Leaks lo confundia con una fuga de "issue_policy" como nombre de tool)
const apiFailureData = $('Detect API Failure').first().json;
const dbResult = $input.first().json;

return [{
  json: {
    ...apiFailureData,
    conversationPhase: dbResult.conversation_phase || apiFailureData.conversationPhase,
    rateLimitData: dbResult.rate_limit_data || apiFailureData.rateLimitData || {}
  }
}];

const input = $input.first().json;
const rawOutput = input.output || '';

const VALID_PHASES = [
  'greeting', 'data_capture', 'summary_confirmation',
  'policy_issuance', 'payment_pending', 'completed'
];

const phaseMarkerRegex = /\[phase:([\w_]+)\]/i;
const match = rawOutput.match(phaseMarkerRegex);

let detectedPhase = null;
let cleanOutput = rawOutput;

if (match) {
  const candidate = match[1].toLowerCase();
  if (VALID_PHASES.includes(candidate)) {
    detectedPhase = candidate;
  } else {
    console.log('Phase Extractor: unknown phase value', { candidate, sessionId: input.sessionId });
  }
  // Strip marker regardless of validity
  cleanOutput = rawOutput.replace(phaseMarkerRegex, '').trimEnd();
} else {
  console.log('Phase Extractor: no phase marker found', {
    sessionId: input.sessionId,
    snippet: rawOutput.substring(0, 100)
  });
}

return [{
  json: {
    ...input,
    output: cleanOutput,
    detectedPhase: detectedPhase,
    phaseMarkerFound: match !== null,
    phaseUpdateRequired: detectedPhase !== null && detectedPhase !== input.conversationPhase
  }
}];

const input = $input.first().json;
console.log('Ban Guard: permanent block', { sessionId: input.sessionId, phoneNumber: input.phoneNumber });

return [{
  json: {
    output: "Lo sentimos, tu acceso a este servicio ha sido suspendido por uso inapropiado. Para asistencia, comunícate con Quálitas al (55) 5258-2880.",
    blocked: true,
    reason: "user_banned",
    sessionId: input.sessionId,
    phoneNumber: input.phoneNumber
  }
}];

// Intent Router (Haiku) returns a text response — parse the JSON intent
const chainOutput = $input.first().json;

// Haiku response is in .text or .output depending on chain configuration
const rawText = chainOutput.text || chainOutput.output || '';

let intent = 'contracting'; // safe default

try {
  // Strip markdown code fences if Haiku wraps in ```json
  const cleaned = rawText.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  const parsed = JSON.parse(cleaned);
  const VALID_INTENTS = ['kb_query', 'contracting', 'out_of_scope'];
  if (parsed.intent && VALID_INTENTS.includes(parsed.intent)) {
    intent = parsed.intent;
  } else {
    console.warn('Parse Router Output: unknown intent, defaulting to contracting', { parsed, rawText });
  }
} catch (e) {
  console.warn('Parse Router Output: JSON parse failed, defaulting to contracting', { rawText, error: e.message });
}

// Retrieve original session context (before Intent Router overwrote the pipeline)
const sessionCtx = $('Restore Context After Guardrail').first().json;

// Override determinístico: en data_capture, una respuesta corta y sin espacios
// (ej. homoclave de 3 caracteres) NUNCA es out_of_scope -- es casi siempre la
// respuesta directa a lo último que pidió el bot. No dependemos de que Haiku
// tenga contexto de fase para clasificarlo bien.
const isShortDataCaptureReply =
  sessionCtx.conversationPhase === 'data_capture' &&
  typeof sessionCtx.chatInput === 'string' &&
  /^[A-Za-z0-9]{1,6}$/.test(sessionCtx.chatInput.trim());

if (isShortDataCaptureReply && intent === 'out_of_scope') {
  intent = 'contracting';
}

// Override determinístico #2: preguntas sobre MSI/meses sin intereses en data_capture
// tampoco son out_of_scope -- deben ir a kb_query para que RAG conteste con el detalle
// real del KB (bancos participantes, excepciones por plazo), no al fallback generico.
const isMsiQuery =
  sessionCtx.conversationPhase === 'data_capture' &&
  typeof sessionCtx.chatInput === 'string' &&
  /\bmsi\b|meses\s+sin\s+intereses/i.test(sessionCtx.chatInput);

if (isMsiQuery && intent === 'out_of_scope') {
  intent = 'kb_query';
}

return [{
  json: {
    ...sessionCtx,
    routedIntent: intent,
    routerRawOutput: rawText
  }
}];

const input = $input.first().json;
const currentAttempts = input.outOfScopeAttempts || 0;
const newAttempts = currentAttempts + 1;

console.log('Out-of-scope attempt', {
  sessionId: input.sessionId,
  attempts: newAttempts,
  message: input.chatInput?.substring(0, 80)
});

return [{
  json: {
    ...input,
    newOutOfScopeAttempts: newAttempts,
    shouldBan: newAttempts >= 3
  }
}];

// Postgres RETURNING replaces pipeline — restore session context
const original = $('Increment Out of Scope').first().json;
const dbResult = $input.first().json;

return [{
  json: {
    ...original,
    outOfScopeAttempts: dbResult.out_of_scope_attempts,
    isBanned: dbResult.is_banned,
    shouldBan: original.shouldBan
  }
}];

const input = $input.first().json;
console.log('Out-of-scope: user banned', { sessionId: input.sessionId, attempts: input.outOfScopeAttempts });

return [{
  json: {
    output: "Tu acceso ha sido suspendido por realizar preguntas fuera del alcance de este servicio. Solo podemos atender consultas relacionadas con seguros de auto Quálitas. Para asistencia directa, llama al (55) 5258-2880.",
    blocked: true,
    reason: "user_banned_out_of_scope",
    sessionId: input.sessionId,
    phoneNumber: input.phoneNumber
  }
}];

const input = $input.first().json;
const attempts = input.outOfScopeAttempts || 1;
const remaining = 3 - attempts;

let message;
if (remaining === 2) {
  message = "Solo puedo ayudarte con información sobre seguros de auto Quálitas y el proceso de contratación. ¿Te puedo asistir con algo relacionado a tu póliza?";
} else if (remaining === 1) {
  message = `Solo puedo atender temas relacionados con seguros de auto. Este es tu ${attempts}° intento fuera del tema — si continúas, tu acceso será suspendido. ¿Deseas continuar con tu contratación o tienes alguna pregunta sobre coberturas?`;
} else {
  // attempts === 2, remaining === 1 already covered above; this is a fallback
  message = "Este servicio está dedicado exclusivamente a seguros de auto Quálitas. Por favor, limita tus preguntas a este tema.";
}

console.log('Out-of-scope warning', { sessionId: input.sessionId, attempts, remaining });

return [{
  json: {
    output: message,
