const input = $input.first().json;
const rawOutput = input.output || '';

const VALID_PHASES = [
  'greeting', 'data_capture', 'summary_confirmation',
  'policy_issuance', 'payment_pending', 'completed'
];

const phaseMarkerRegex = /\[phase:([\w_]+)\]/i;
const match = rawOutput.match(phaseMarkerRegex);

let detectedPhase = null;
let cleanOutput = rawOutput;

if (match) {
  const candidate = match[1].toLowerCase();
  if (VALID_PHASES.includes(candidate)) {
    detectedPhase = candidate;
  } else {
    console.log('Phase Extractor: unknown phase value', { candidate, sessionId: input.sessionId });
  }
  // Strip marker regardless of validity
  cleanOutput = rawOutput.replace(phaseMarkerRegex, '').trimEnd();
} else {
  console.log('Phase Extractor: no phase marker found', {
    sessionId: input.sessionId,
    snippet: rawOutput.substring(0, 100)
  });
}

return [{
  json: {
    ...input,
    output: cleanOutput,
    detectedPhase: detectedPhase,
    phaseMarkerFound: match !== null,
