const trimmedInput = (ctx.chatInput || '').trim();
const digitSelection = /^[1-9][0-9]?$/.test(trimmedInput) ? parseInt(trimmedInput, 10) : null;

let sessionResolved = false;
let needsDisambiguation = false;
let sessionRow = null;
let resolvedLookupMode = ctx.lookupMode;

if (ctx.lookupMode === 'payload_v2' || ctx.lookupMode === 'payload_v1') {
  if (matchCount >= 1) {
    sessionRow = matches[0];
