  if (matchCount === 1) {
    sessionRow = matches[0];
    sessionResolved = true;
  } else if (matchCount > 1) {
    if (digitSelection && digitSelection <= matchCount) {
      sessionRow = matches[digitSelection - 1];
      sessionResolved = true;
      resolvedLookupMode = 'disambiguation_text_selection';
