  return `${i + 1}. #${c.quotation_id} ${vehiculo} · ${cobertura} · ${formaPago} · ${fmtMoney(monto)} · ${fecha}`;
});

const message = `Encontré ${candidates.length} cotizaciones activas para este número:\n\n${lines.join('\n')}\n\nElige cuál quieres continuar.`;

