const visionResponse = $input.first().json;
const rawText = visionResponse?.content?.[0]?.text || '';
const original = $('Image Budget Guard').first().json;

const VIN_REGEX = /^[A-HJ-NPR-Z0-9]{17}$/;
const PLACAS_REGEX = /^[A-Z0-9]{6,7}$/;

let vin = null, vinConfidence = 'baja', placas = null, placasConfidence = 'baja', motivo = null;
try {
  const cleaned = rawText.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  vin = parsed.vin || null;
  vinConfidence = parsed.vin_confidence || 'baja';
  placas = parsed.placas || null;
  placasConfidence = parsed.placas_confidence || 'baja';
  motivo = parsed.motivo || null;
} catch (e) {
  motivo = 'No se pudo parsear la respuesta del modelo de visión';
  console.log('Parse VIN Extraction: fallo de parseo', { sessionId: original.sessionId, rawText: rawText.slice(0, 200) });
}

const vinValid = typeof vin === 'string' && VIN_REGEX.test(vin) && vinConfidence === 'alta';
const placasNormalized = typeof placas === 'string' ? placas.toUpperCase().replace(/[^A-Z0-9]/g, '') : null;
const placasValid = typeof placasNormalized === 'string' && PLACAS_REGEX.test(placasNormalized) && placasConfidence === 'alta';

const parts = [];
if (vinValid) parts.push(`número de serie detectado: ${vin}`);
if (placasValid) parts.push(`placas detectadas: ${placasNormalized}`);

let chatInput;
if (parts.length > 0) {
  chatInput = `[FOTO_VIN] El cliente adjuntó una foto de su tarjeta de circulación. ${parts.join('; ')}.`;
} else {
  chatInput = `[FOTO_VIN] El cliente adjuntó una imagen, pero no se detectaron datos legibles del vehículo.`;
}

return [{
  json: {
    ...original,
    chatInput,
    imageExtractionResult: {
      vin, vinConfidence, vinValid,
      placas: placasNormalized, placasConfidence, placasValid,
      motivo
    }
  }
}];

const parsed = $('Parse VIN Extraction').first().json;
const dbResult = $input.first().json;

return [{
