function isFailedToolCallLeak(text) {
  if (!text) return false;
  if (text.includes('<invoke') || text.includes('<parameter name=')) return true;
  const m = text.match(/^Calling \w+ with input:?\s*([\s\S]*)$/);
  if (!m) return false;
  const rest = m[1].trim();
  if (!rest) return true;
  try {
